LTimer = {}

local LTimer = LTimer
local mt = {__index = LTimer}

--unscaled false 采用deltaTime计时，true 采用 unscaledDeltaTime计时
function LTimer.New(func, duration, loop, unscaled)
    unscaled = unscaled or false and true
    loop = loop or 1
    return setmetatable({func = func, duration = duration, time = duration, loop = loop, unscaled = unscaled, running = false}, mt)
end

function LTimer:Start()
    self.running = true

    LxTimer.timerList[self] = self

    if not self.handle then
        self.handle = UpdateBeat:CreateListener(self.Update, self)
    end

    UpdateBeat:AddListener(self.handle)
end

function LTimer:Reset(func, duration, loop, unscaled)
    self.duration 	= duration
    self.loop		= loop or 1
    self.unscaled	= unscaled
    self.func		= func
    self.time		= duration
end

function LTimer:Stop()
    self.running = false

    LxTimer.timerList[self] = nil

    if self.handle then
        UpdateBeat:RemoveListener(self.handle)
    end
end

function LTimer:Update()
    if self.pausing then
        return
    end
    if not self.running then
        return
    end

    local delta = self.unscaled and Time.unscaledDeltaTime or Time.deltaTime
    self.time = self.time - delta

    if self.time <= 0 then
        if self.func then self.func() end

        if self.loop > 0 then
            self.loop = self.loop - 1
            self.time = self.time + self.duration
        end

        if self.loop == 0 then
            self:Stop()
        elseif self.loop < 0 then
            self.time = self.time + self.duration
        end
    end
end

function LTimer:SetDuration(duration)
    self.duration = duration
end

function LTimer:Pause(bPause)
    self.pausing = bPause
end
