function LFrameTimer.New(func, count, loop)
    local c = Time.frameCount + count
    loop = loop or 1
    return setmetatable({func = func, loop = loop, duration = count, count = c, running = false}, mt2)
end

function LFrameTimer:Reset(func, count, loop)
    self.func = func
    self.duration = count
    self.loop = loop
    self.count = Time.frameCount + count
end

function LFrameTimer:Start()
    if not self.handle then
        self.handle = CoUpdateBeat:CreateListener(self.Update, self)
    end
    LxTimer.timerList[self] = self

    CoUpdateBeat:AddListener(self.handle)
    self.running = true
end

function LFrameTimer:Stop()
    self.running = false

    LxTimer.timerList[self] = nil

    if self.handle then
        CoUpdateBeat:RemoveListener(self.handle)
    end
end

function LFrameTimer:Update()
    if not self.running then
        return
    end

    if Time.frameCount >= self.count then
        self.func()

        if self.loop > 0 then
            self.loop = self.loop - 1
        end

        if self.loop == 0 then
            self:Stop()
        else
            self.count = Time.frameCount + self.duration
        end
    end
end

